11	fn switch(route: Route) -> Html {
12	    match route {
13	        Route::Login => html! { <LoginPage /> },
14	        Route::Unauthorized => html! { <UnauthorizedPage /> },
15	        Route::Admin | Route::AdminUsers | Route::AdminDeletionRequests => {
16	            html! { <RoleGuard required_role="Administrator"><AdminShell /></RoleGuard> }
17	        }
18	        Route::TeacherClasses => {
19	            html! { <RoleGuard required_role="Teacher"><TeacherClassesShell /></RoleGuard> }
20	        }
21	        Route::Home | Route::NotFound => html! { <AuthGuard /> },
22	    }
23	}
