25	#[function_component(AuthGuard)]
26	fn auth_guard() -> Html {
27	    let state = use_context::<AppStateContext>().expect("AppState context not found");
28	    let navigator = use_navigator().unwrap();
29	    let authenticated = state.is_authenticated();
30	
31	    // Hooks must be called unconditionally — redirect happens inside the effect
32	    {
33	        let navigator = navigator.clone();
34	        use_effect_with(authenticated, move |&auth| {
35	            if !auth {
36	                navigator.push(&Route::Login);
37	            }
38	        });
39	    }
40	
41	    if authenticated {
42	        html! { <HomePage /> }
43	    } else {
44	        html! { <div class="loading">{ "Redirecting\u{2026}" }</div> }
45	    }
46	}
