48	#[derive(Properties, PartialEq)]
49	pub struct RoleGuardProps {
50	    pub required_role: &'static str,
51	    pub children: Children,
52	}
53	
54	#[function_component(RoleGuard)]
55	fn role_guard(props: &RoleGuardProps) -> Html {
56	    let state = use_context::<AppStateContext>().expect("AppState context not found");
57	    let navigator = use_navigator().unwrap();
58	    let authenticated = state.is_authenticated();
59	    let has_role = state.has_role(props.required_role);
60	
61	    let role = props.required_role;
62	    use_effect_with((authenticated, has_role), move |(auth, role_ok)| {
63	        if !auth {
64	            navigator.push(&Route::Login);
65	        } else if !role_ok {
66	            navigator.push(&Route::Unauthorized);
67	        }
68	        let _ = role; // suppress unused warning
69	    });
70	
71	    if authenticated && has_role {
72	        html! { for props.children.iter() }
73	    } else if authenticated && !has_role {
74	        html! { <UnauthorizedPage /> }
75	    } else {
76	        html! { <div class="loading">{ "Checking access\u{2026}" }</div> }
77	    }
78	}
