100	#[function_component(App)]
101	pub fn app() -> Html {
102	    let app_state = use_state(AppState::default);
103	
104	    // On mount, if we have a stored token, validate it by fetching the current user.
105	    {
106	        let app_state = app_state.clone();
107	        use_effect_with((), move |_| {
108	            let app_state = app_state.clone();
109	            if let Some(token) = (*app_state).token.clone() {
110	                wasm_bindgen_futures::spawn_local(async move {
111	                    match auth::me(&token).await {
112	                        Ok(user) => {
113	                            let mut new_state = (*app_state).clone();
114	                            new_state.user = Some(user);
115	                            app_state.set(new_state);
116	                        }
117	                        Err(_) => {
118	                            // Token is invalid or expired — clear it.
119	                            let mut new_state = (*app_state).clone();
120	                            new_state.logout();
121	                            app_state.set(new_state);
122	                        }
123	                    }
124	                });
125	            }
126	        });
127	    }
128	
129	    let on_logout = {
130	        let app_state = app_state.clone();
131	        Callback::from(move |_: ()| {
132	            let token = (*app_state).token.clone();
133	            let app_state = app_state.clone();
134	            wasm_bindgen_futures::spawn_local(async move {
135	                if let Some(t) = token {
136	                    let _ = auth::logout(&t).await;
137	                }
138	                let mut new_state = (*app_state).clone();
139	                new_state.logout();
140	                app_state.set(new_state);
141	            });
142	        })
143	    };
144	
145	    html! {
146	        <ContextProvider<AppStateContext> context={app_state.clone()}>
147	            <BrowserRouter>
148	                <div id="app">
149	                    <Layout on_logout={on_logout}>
150	                        <Switch<Route> render={switch} />
151	                    </Layout>
152	                </div>
153	            </BrowserRouter>
154	        </ContextProvider<AppStateContext>>
155	    }
156	}
