5	/// Classified login error for richer UX feedback.
6	#[derive(Debug, Clone, PartialEq)]
7	pub enum LoginError {
8	    /// Wrong credentials (401) — generic, don't reveal username existence
9	    InvalidCredentials,
10	    /// Rate limited / locked out (429)
11	    TooManyAttempts(String),
12	    /// Account blocked — includes specific message from server (403)
13	    AccountBlocked(String),
14	    /// Validation error (422)
15	    ValidationError(String),
16	    /// Network or unexpected error
17	    NetworkError(String),
18	}
19	
20	impl LoginError {
21	    /// Returns the user-visible message for this error.
22	    pub fn display_message(&self) -> &str {
23	        match self {
24	            LoginError::InvalidCredentials => "Invalid username or password.",
25	            LoginError::TooManyAttempts(msg) => msg.as_str(),
26	            LoginError::AccountBlocked(msg) => msg.as_str(),
27	            LoginError::ValidationError(msg) => msg.as_str(),
28	            LoginError::NetworkError(_) => "A connection error occurred. Please try again.",
29	        }
30	    }
31	
32	    /// CSS class suffix for styling the error banner
33	    pub fn css_class(&self) -> &str {
34	        match self {
35	            LoginError::InvalidCredentials => "error-invalid",
36	            LoginError::TooManyAttempts(_) => "error-lockout",
37	            LoginError::AccountBlocked(_) => "error-blocked",
38	            LoginError::ValidationError(_) => "error-validation",
39	            LoginError::NetworkError(_) => "error-network",
40	        }
41	    }
42	}
