44	#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
45	pub struct UserPublic {
46	    pub id: String,
47	    pub username: String,
48	    pub email: String,
49	    pub display_name: Option<String>,
50	    pub account_state: String,
51	    pub roles: Vec<String>,
52	    pub created_at: String,
53	}
54	
55	#[derive(Debug, Clone, PartialEq)]
56	pub struct AppState {
57	    pub user: Option<UserPublic>,
58	    pub token: Option<String>,
59	    pub loading: bool,
60	}
61	
