        let token = login_as(&app, &format!("ci_student_{}", suffix)).await;
        let req = TestRequest::post()
            .uri(&format!("/api/v1/check-ins/windows/{}/submit", window_id))
            .insert_header(("Authorization", format!("Bearer {}", token)))
