use chrono::{DateTime, Utc};
use serde::Serialize;
use uuid::Uuid;

use crate::db::DbPool;
use crate::errors::AppError;
use crate::middleware::auth::AuthContext;

// ---------------------------------------------------------------------------
// Route configuration
// ---------------------------------------------------------------------------

pub fn configure(cfg: &mut web::ServiceConfig) {
    cfg.service(
        web::scope("/notifications")
            // Register the static sub-path before the dynamic one so actix-web
            // matches /unread-count before trying to parse it as a UUID.
            .route("/unread-count", web::get().to(unread_count))
            .route("", web::get().to(list_notifications))
            .route("/{id}/read", web::post().to(mark_read)),
    );
}

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

#[derive(sqlx::FromRow, Serialize)]
struct NotificationRow {
    id: Uuid,
    subject: String,
    body: String,
    notification_type: String,
    read_at: Option<DateTime<Utc>>,
    created_at: DateTime<Utc>,
    sender_username: Option<String>,
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

/// GET /api/v1/notifications
///
/// Returns the calling user's inbox, newest first, limited to 50 items.
async fn list_notifications(
    pool: web::Data<DbPool>,
    auth: AuthContext,
) -> Result<HttpResponse, AppError> {
    let notifications = sqlx::query_as::<_, NotificationRow>(
        "SELECT
           n.id,
           n.subject,
           n.body,
           n.notification_type,
           n.read_at,
           n.created_at,
           s.username AS sender_username
         FROM notifications n
         LEFT JOIN users s ON n.sender_id = s.id
         WHERE n.recipient_id = $1
           AND (n.expires_at IS NULL OR n.expires_at > NOW())
         ORDER BY n.created_at DESC
         LIMIT 50",
    )
    .bind(auth.0.user_id)
    .fetch_all(pool.get_ref())
    .await?;

    Ok(HttpResponse::Ok().json(notifications))
}

/// GET /api/v1/notifications/unread-count
///
/// Returns the count of unread (non-expired) notifications for the calling user.
async fn unread_count(
    pool: web::Data<DbPool>,
    auth: AuthContext,
) -> Result<HttpResponse, AppError> {
    let count: i64 = sqlx::query_scalar(
        "SELECT COUNT(*) FROM notifications
         WHERE recipient_id = $1
           AND read_at IS NULL
           AND (expires_at IS NULL OR expires_at > NOW())",
    )
    .bind(auth.0.user_id)
    .fetch_one(pool.get_ref())
    .await?;

    Ok(HttpResponse::Ok().json(serde_json::json!({ "unread": count })))
}

/// POST /api/v1/notifications/{id}/read
///
/// Marks a notification as read. Silently succeeds if already read.
/// Returns 404 if the notification does not belong to the calling user.
async fn mark_read(
    pool: web::Data<DbPool>,
    auth: AuthContext,
    path: web::Path<Uuid>,
) -> Result<HttpResponse, AppError> {
    let notification_id = path.into_inner();

    // Verify ownership before updating.
    let owner: Option<Uuid> = sqlx::query_scalar(
        "SELECT recipient_id FROM notifications WHERE id = $1",
    )
    .bind(notification_id)
    .fetch_optional(pool.get_ref())
    .await?;

    match owner {
