        "UPDATE notifications SET read_at = NOW()
         WHERE id = $1 AND read_at IS NULL",
    )
    .bind(notification_id)
    .execute(pool.get_ref())
    .await?;

    Ok(HttpResponse::Ok().json(serde_json::json!({ "message": "Marked as read." })))
}
"}

