7	pub fn hash_password(password: &str) -> Result<String, AppError> {
8	    if password.len() < 12 {
9	        return Err(AppError::ValidationError(
10	            "Password must be at least 12 characters".into(),
11	        ));
12	    }
13	    let salt = SaltString::generate(&mut OsRng);
14	    let hash = Argon2::default()
15	        .hash_password(password.as_bytes(), &salt)
16	        .map_err(|e| AppError::InternalError(e.to_string()))?
17	        .to_string();
18	    Ok(hash)
19	}
20	
21	pub fn verify_password(password: &str, hash: &str) -> Result<(), AppError> {
22	    let parsed = PasswordHash::new(hash)
23	        .map_err(|e| AppError::InternalError(e.to_string()))?;
24	    Argon2::default()
25	        .verify_password(password.as_bytes(), &parsed)
26	        .map_err(|_| AppError::Unauthorized("Invalid password".into()))
27	}
