23	pub async fn get<T: DeserializeOwned>(path: &str, token: Option<&str>) -> Result<T, ApiError> {
24	    let url = format!("{}{}", API_BASE, path);
25	    let mut req = Request::get(&url);
26	    if let Some(t) = token {
27	        req = req.header("Authorization", &format!("Bearer {}", t));
28	    }
29	    let resp = req
30	        .send()
31	        .await
32	        .map_err(|e| ApiError::Network(e.to_string()))?;
33	    if resp.status() >= 400 {
34	        let msg = resp.text().await.unwrap_or_default();
35	        return Err(ApiError::Http {
36	            status: resp.status(),
37	            message: msg,
