7	pub enum LoginError {
8	    /// Wrong credentials (401) — generic, don't reveal username existence
9	    InvalidCredentials,
10	    /// Rate limited / locked out (429)
11	    TooManyAttempts(String),
12	    /// Account blocked — includes specific message from server (403)
13	    AccountBlocked(String),
14	    /// Validation error (422)
15	    ValidationError(String),
16	    /// Network or unexpected error
17	    NetworkError(String),
18	}
