114	        use_effect_with((), move |_| {
115	            let app_state = app_state.clone();
116	            if let Some(token) = (*app_state).token.clone() {
117	                wasm_bindgen_futures::spawn_local(async move {
118	                    match auth::me(&token).await {
119	                        Ok(user) => {
120	                            let mut new_state = (*app_state).clone();
121	                            new_state.user = Some(user);
122	                            app_state.set(new_state);
123	                        }
124	                        Err(_) => {
125	                            // Token is invalid or expired — clear it.
126	                            let mut new_state = (*app_state).clone();
127	                            new_state.logout();
128	                            app_state.set(new_state);
129	                        }
130	                    }
131	                });
132	            }
133	        });
134	    }
135	
136	    let on_logout = {
137	        let app_state = app_state.clone();
138	        Callback::from(move |_: ()| {
139	            let token = (*app_state).token.clone();
140	            let app_state = app_state.clone();
141	            wasm_bindgen_futures::spawn_local(async move {
142	                if let Some(t) = token {
143	                    let _ = auth::logout(&t).await;
144	                }
145	                let mut new_state = (*app_state).clone();
146	                new_state.logout();
147	                app_state.set(new_state);
148	            });
149	        })
150	    };
151	
152	    html! {
153	        <ContextProvider<AppStateContext> context={app_state.clone()}>
154	            <BrowserRouter>
155	                <div id="app">
156	                    <Layout on_logout={on_logout}>
157	                        <Switch<Route> render={switch} />
158	                    </Layout>
159	                </div>
160	            </BrowserRouter>
161	        </ContextProvider<AppStateContext>>
162	    }
163	}
