18	    let body = LoginRequest { username, password };
19	    match post::<LoginRequest, LoginResponse>("/auth/login", &body, None).await {
20	        Ok(resp) => Ok(resp),
21	        Err(ApiError::Http { status, message }) => {
22	            // Parse the server's JSON error body to extract the "error" field
23	            let server_msg = serde_json::from_str::<serde_json::Value>(&message)
24	                .ok()
25	                .and_then(|v| v["error"].as_str().map(|s| s.to_string()))
26	                .unwrap_or_else(|| message.clone());
27	
