30	                429 => Err(LoginError::TooManyAttempts(server_msg)),
31	                403 => Err(LoginError::AccountBlocked(server_msg)),
32	                422 => Err(LoginError::ValidationError(server_msg)),
33	                _ => Err(LoginError::NetworkError(format!("HTTP {}: {}", status, server_msg))),
34	            }
35	        }
36	        Err(ApiError::Network(e)) => Err(LoginError::NetworkError(e)),
